#!/usr/bin/env node
/**
 * Graph Topology Analysis Script for Tour Builder
 *
 * Analyzes graph topology to surface structural signals useful for tour design:
 * - Fan-in/fan-out rankings
 * - Entry point candidates
 * - Dependency chains (BFS)
 * - Non-code file inventory
 * - Tightly coupled clusters
 * - Layer list
 * - Node summary index
 */

const fs = require('fs');

function main() {
    const inputPath = process.argv[2];
    const outputPath = process.argv[3];

    if (!inputPath || !outputPath) {
        console.error('Usage: node ua-tour-analyze.js <input.json> <output.json>');
        process.exit(1);
    }

    let inputData;
    try {
        inputData = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
    } catch (e) {
        console.error('Error reading input file:', e.message);
        process.exit(1);
    }

    const nodes = inputData.nodes || [];
    const edges = inputData.edges || [];
    const layers = inputData.layers || [];

    // Build lookup maps
    const nodeMap = {};
    nodes.forEach(n => { nodeMap[n.id] = n; });

    // Fan-in and Fan-out computation
    const fanIn = {};  // count of edges pointing TO this node
    const fanOut = {}; // count of edges this node points TO

    nodes.forEach(n => {
        fanIn[n.id] = 0;
        fanOut[n.id] = 0;
    });

    edges.forEach(e => {
        const src = e.source;
        const tgt = e.target;
        if (fanOut[src] !== undefined) fanOut[src]++;
        if (fanIn[tgt] !== undefined) fanIn[tgt]++;
    });

    // A. Fan-In Ranking (Importance) - top 20
    const fanInRanking = nodes
        .map(n => ({ id: n.id, fanIn: fanIn[n.id] || 0, name: n.name }))
        .sort((a, b) => b.fanIn - a.fanIn)
        .slice(0, 20);

    // B. Fan-Out Ranking (Scope) - top 20
    const fanOutRanking = nodes
        .map(n => ({ id: n.id, fanOut: fanOut[n.id] || 0, name: n.name }))
        .sort((a, b) => b.fanOut - a.fanOut)
        .slice(0, 20);

    // C. Entry Point Candidates
    const entryPointCandidates = nodes.map(n => {
        let score = 0;
        const name = n.name || '';
        const filePath = n.filePath || '';

        // Code file scoring
        if (n.type === 'file') {
            const entryFilenames = ['index.ts', 'index.js', 'main.ts', 'main.js', 'app.ts', 'app.js',
                'server.ts', 'server.js', 'mod.rs', 'main.go', 'main.py', 'main.rs',
                'manage.py', 'app.py', 'wsgi.py', 'asgi.py', 'run.py', '__main__.py',
                'Application.java', 'Main.java', 'Program.cs', 'config.ru', 'index.php',
                'App.swift', 'Application.kt', 'main.cpp', 'main.c', 'Coredump.java'];
            if (entryFilenames.some(f => name.endsWith(f))) score += 3;

            // File at project root or one level deep
            const depth = filePath.split('/').length;
            if (depth <= 2) score += 1;

            // High fan-out (top 10%)
            const fanOutThreshold = nodes.length * 0.1;
            if ((fanOut[n.id] || 0) >= fanOutThreshold) score += 1;

            // Low fan-in (bottom 25%)
            const fanInValues = Object.values(fanIn).sort((a, b) => a - b);
            const bottom25 = fanInValues[Math.floor(fanInValues.length * 0.25)] || 0;
            if ((fanIn[n.id] || 0) <= bottom25) score += 1;
        }

        // Documentation file scoring
        if (n.type === 'document') {
            if (name === 'README.md' && filePath === 'README.md') score += 5;
            else if (name.endsWith('.md') && depth <= 2) score += 2;
        }

        return { id: n.id, score, name, summary: n.summary || '' };
    }).filter(c => c.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);

    // D. Dependency Chains (BFS from Entry Point)
    // Find top code entry point (skip documentation)
    const topCodeEntry = entryPointCandidates.find(c => {
        const node = nodeMap[c.id];
        return node && node.type === 'file';
    });

    let bfsTraversal = {
        startNode: null,
        order: [],
        depthMap: {},
        byDepth: {}
    };

    if (topCodeEntry) {
        const startNodeId = topCodeEntry.id;
        const importsEdges = edges.filter(e => e.type === 'imports' || e.type === 'calls');

        // Build adjacency map
        const adj = {};
        importsEdges.forEach(e => {
            if (!adj[e.source]) adj[e.source] = [];
            adj[e.source].push(e.target);
        });

        // BFS
        const visited = new Set();
        const queue = [{ nodeId: startNodeId, depth: 0 }];
        visited.add(startNodeId);

        while (queue.length > 0) {
            const { nodeId, depth } = queue.shift();

            bfsTraversal.order.push(nodeId);
            bfsTraversal.depthMap[nodeId] = depth;

            if (!bfsTraversal.byDepth[depth]) bfsTraversal.byDepth[depth] = [];
            bfsTraversal.byDepth[depth].push(nodeId);

            const neighbors = adj[nodeId] || [];
            neighbors.forEach(neighbor => {
                if (!visited.has(neighbor)) {
                    visited.add(neighbor);
                    queue.push({ nodeId: neighbor, depth: depth + 1 });
                }
            });
        }

        bfsTraversal.startNode = startNodeId;
    }

    // E. Non-Code File Inventory
    const nonCodeFiles = {
        documentation: [],
        infrastructure: [],
        data: [],
        config: []
    };

    nodes.forEach(n => {
        const entry = { id: n.id, name: n.name, summary: n.summary || '' };
        switch (n.type) {
            case 'document':
                nonCodeFiles.documentation.push(entry);
                break;
            case 'service':
            case 'pipeline':
            case 'resource':
                nonCodeFiles.infrastructure.push(entry);
                break;
            case 'table':
            case 'schema':
            case 'endpoint':
                nonCodeFiles.data.push(entry);
                break;
            case 'config':
                nonCodeFiles.config.push(entry);
                break;
        }
    });

    // F. Tightly Coupled Clusters
    // Find bidirectional relationships (A imports B AND B imports A, or A calls B AND B calls A)
    const importMap = {};
    edges.filter(e => e.type === 'imports' || e.type === 'calls').forEach(e => {
        if (!importMap[e.source]) importMap[e.source] = new Set();
        importMap[e.source].add(e.target);
    });

    const clusters = [];
    const clusteredNodes = new Set();

    // Find pairs with bidirectional edges
    edges.forEach(e => {
        if (e.type !== 'imports' && e.type !== 'calls') return;
        const reverse = importMap[e.target] && importMap[e.target].has(e.source);
        if (reverse && !clusteredNodes.has(e.source) && !clusteredNodes.has(e.target)) {
            const cluster = [e.source, e.target];
            clusteredNodes.add(e.source);
            clusteredNodes.add(e.target);
            clusters.push({ nodes: cluster, edgeCount: 2 });
        }
    });

    // Expand clusters by adding nodes connected to 2+ existing cluster members
    clusters.forEach(cluster => {
        const members = new Set(cluster.nodes);
        let changed = true;
        while (changed) {
            changed = false;
            edges.forEach(e => {
                if (cluster.nodes.length >= 5) return;
                const srcMember = members.has(e.source);
                const tgtMember = members.has(e.target);
                if (srcMember && !tgtMember && !clusteredNodes.has(e.target)) {
                    // Check if e.target connects to 2+ cluster members
                    let connCount = 0;
                    edges.forEach(e2 => {
                        if (e2.source === e.target && members.has(e2.target)) connCount++;
                        if (e2.target === e.target && members.has(e2.source)) connCount++;
                    });
                    if (connCount >= 2) {
                        cluster.nodes.push(e.target);
                        members.add(e.target);
                        clusteredNodes.add(e.target);
                        changed = true;
                    }
                }
                if (tgtMember && !srcMember && !clusteredNodes.has(e.source)) {
                    let connCount = 0;
                    edges.forEach(e2 => {
                        if (e2.source === e.source && members.has(e2.target)) connCount++;
                        if (e2.target === e.source && members.has(e2.source)) connCount++;
                    });
                    if (connCount >= 2) {
                        cluster.nodes.push(e.source);
                        members.add(e.source);
                        clusteredNodes.add(e.source);
                        changed = true;
                    }
                }
            });
        }
    });

    // G. Layer List
    const layerList = layers.map(l => ({
        id: l.id,
        name: l.name,
        description: l.description
    }));

    // H. Node Summary Index
    const nodeSummaryIndex = {};
    nodes.forEach(n => {
        nodeSummaryIndex[n.id] = {
            name: n.name,
            type: n.type,
            summary: n.summary || ''
        };
    });

    // Build output
    const output = {
        scriptCompleted: true,
        entryPointCandidates,
        fanInRanking,
        fanOutRanking,
        bfsTraversal,
        nonCodeFiles,
        clusters: clusters.slice(0, 10),
        layers: {
            count: layerList.length,
            list: layerList
        },
        nodeSummaryIndex,
        totalNodes: nodes.length,
        totalEdges: edges.length
    };

    try {
        fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
        console.log('Analysis complete. Output written to:', outputPath);
        process.exit(0);
    } catch (e) {
        console.error('Error writing output:', e.message);
        process.exit(1);
    }
}

main();

